        const s = num.toString();
        // Check if it's a palindrome
        if (s !== s.split('').reverse().join('')) {
            return false;
        }
        const count: Record<string, number> = {};
        for (const c of s) {
            count[c] = (count[c] || 0) + 1;
        }
        for (const [digit, cnt] of Object.entries(count)) {
            const d = parseInt(digit);
            if (cnt !== d) {
                return false;
            }
        }
        return true;
    }

    let candidate = n + 1;
    while (true) {
        if (isSpecialNumber(candidate)) {
            return candidate;
        }
        candidate++;
    }
}
